#include <stdio.h>

/* == RAPPEL =================================================
 * Structure d'un inode Unix :
 *   - 12 blocs directs (D0..D11)
 *   - 1 bloc indirect simple  (I1)
 *   - 1 bloc indirect double  (I2)
 *   - 1 bloc indirect triple  (I3)
 *
 * Exemple avec BLOCK_SIZE=512, PTR_SIZE=2, fichier 1 Ko :
 *   data_blocks       = 1024 / 512  = 2
 *   entries_per_block = 512  / 2    = 256
 *   direct_ok         = (2 <= 12)   = oui
 * =========================================================== */

#define BLOCK_SIZE   1024
#define PTR_SIZE     2
#define FILE_SIZE    (32 * 1024)
#define DIRECT_BLOCKS 12

int main(void) {
    int data_blocks       = FILE_SIZE / BLOCK_SIZE;
    int entries_per_block = BLOCK_SIZE / PTR_SIZE;
    int direct_ok         = (data_blocks <= DIRECT_BLOCKS) ? 1 : 0;

    printf("Blocs de données: %d\n", data_blocks);
    printf("Entrées par bloc indirect: %d\n", entries_per_block);
    printf("Blocs directs suffisants: %s\n", direct_ok ? "oui" : "non");
    return 0;
}

